import{c as r,Q as e,j as a,m as o}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"东南大学","description":"东南大学生物科学与医学工程学院博士项目指南 — 器官芯片、类脑器官、生物电子学方向","frontmatter":{"title":"东南大学","description":"东南大学生物科学与医学工程学院博士项目指南 — 器官芯片、类脑器官、生物电子学方向","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bme","bci","neuroscience"],"tags":["东南大学","南京",985],"admission-year":2027},"headers":[],"relativePath":"universities/seu.md","filePath":"universities/seu.md","lastUpdated":1780110618000}'),s={name:"universities/seu.md"};function l(n,t,i,d,h,u){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="东南大学" tabindex="-1">东南大学 <a class="header-anchor" href="#东南大学" aria-label="Permalink to &quot;东南大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>东南大学的生物医学工程为国家一级重点学科（2007年获评），在教育部学科评估中长期位列全国第一方阵。<strong>顾忠泽教授领衔的器官芯片研究院</strong>和<strong>数字医学工程全国重点实验室</strong>在类器官芯片、生物电子学方向处于国际前沿。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.seu.edu.cn" target="_blank" rel="noreferrer">https://www.seu.edu.cn</a></li><li>研究生院: <a href="https://seugs.seu.edu.cn" target="_blank" rel="noreferrer">https://seugs.seu.edu.cn</a></li><li>生物科学与医学工程学院: <a href="https://bme.seu.edu.cn" target="_blank" rel="noreferrer">https://bme.seu.edu.cn</a></li></ul><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-器官芯片-类脑器官-生物电子学方向-——" tabindex="-1">—— 器官芯片 / 类脑器官 / 生物电子学方向 —— <a class="header-anchor" href="#——-器官芯片-类脑器官-生物电子学方向-——" aria-label="Permalink to &quot;—— 器官芯片 / 类脑器官 / 生物电子学方向 ——&quot;">​</a></h3><h4 id="顾忠泽-—-首席教授、博导" tabindex="-1">顾忠泽 — 首席教授、博导 <a class="header-anchor" href="#顾忠泽-—-首席教授、博导" aria-label="Permalink to &quot;顾忠泽 — 首席教授、博导&quot;">​</a></h4><ul><li><strong>职称</strong>: 东南大学首席教授、长江学者特聘教授、国家杰出青年基金获得者</li><li><strong>职务</strong>: 器官芯片研究院<strong>院长</strong>、数字医学工程全国重点实验室<strong>主任</strong>、生物科学与医学工程学院<strong>院长</strong></li><li><strong>荣誉</strong>: 美国医学与生物工程院 Fellow、英国皇家化学会 Fellow、中国生物医学工程学会会士</li><li><strong>个人主页</strong>: <a href="https://iirs.seu.edu.cn/2025/0604/c58381a530605/page.htm" target="_blank" rel="noreferrer">https://iirs.seu.edu.cn/2025/0604/c58381a530605/page.htm</a></li></ul><p><strong>研究方向</strong>:</p><ol><li>胶体光子晶体及其在生物医学的应用</li><li>基于三维激光制造的微结构可控材料</li><li><strong>人体器官芯片的制造、测量与应用</strong>（芯片材料、人工器官培养、支持系统）</li><li><strong>基于人工类脑器官的混合智能</strong>（类脑器官培养、电生理信号采集与分析、智能机器人）</li><li>人体器官芯片与AI融合的药物设计（器官芯片大模型、药理/毒理评价）</li></ol><p><strong>学术影响力</strong>:</p><ul><li>在Nature及系列刊物上发表论文<strong>400余篇</strong>，被引<strong>20000余次</strong></li><li>牵头制定并颁布<strong>器官芯片国家标准</strong></li><li>成果入选<strong>2023、2024年中国生命科学十大进展</strong></li><li>获国家自然科学二等奖、国家科技进步二等奖等</li></ul><p><strong>2026年博士生招生</strong>: 是（持续招收博士生及博士后）</p><blockquote><p><strong>关键匹配点</strong>: 顾忠泽的&quot;基于人工类脑器官的混合智能&quot;方向 — 类脑器官培养 + 电生理信号采集与分析 + 智能机器人，与你的脑类器官经验 + EMG信号处理背景高度吻合！</p></blockquote><hr><h2 id="_2026年博士招生" tabindex="-1">2026年博士招生 <a class="header-anchor" href="#_2026年博士招生" aria-label="Permalink to &quot;2026年博士招生&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>时间</th><th>说明</th></tr></thead><tbody><tr><td>招生简章发布</td><td>2025年10月</td><td>东大研招网</td></tr><tr><td>网上报名</td><td>2025年10月-11月</td><td>通过东大研究生招生系统</td></tr><tr><td>综合考核</td><td>2026年3月-4月</td><td>申请考核制</td></tr></tbody></table><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>顾忠泽课题组是最佳匹配之一</strong>：类脑器官混合智能方向直接需要你的脑类器官培养+钙成像+信号处理技能</li><li><strong>器官芯片方向</strong>：你的硕士研究（iPSC类器官+温控系统）经验直接对口</li><li><strong>东大BME学科排名高</strong>：国家一级重点学科，毕业认可度好</li><li><strong>东大BME有跨尺度制造特色</strong>：器官芯片涉及微流控，你的硬件开发经验是加分项</li><li><strong>建议在联系邮件中突出</strong>：脑类器官培养经验 + 钙成像系统开发能力 + EMG电生理信号处理技术 — 三位一体匹配类脑器官混合智能方向</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="https://iirs.seu.edu.cn/2025/0604/c58381a530605/page.htm" target="_blank" rel="noreferrer">顾忠泽主页</a>（访问日期: 2026-05-25）</li><li><a href="https://bme.seu.edu.cn" target="_blank" rel="noreferrer">BME学院</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以东南大学研究生院官网最新公告为准。</em></p>',28)])])}const p=r(s,[["render",l]]);export{c as __pageData,p as default};
